import{_ as r,o as t,c as n,j as e,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"11、正义【XI】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/11、正义【XI】.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/11、正义【XI】.md"}'),o={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/11、正义【XI】.md"};function d(_,a,i,l,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_11、正义【xi】",tabindex:"-1"},[p("11、正义【XI】 "),e("a",{class:"header-anchor",href:"#_11、正义【xi】","aria-label":'Permalink to "11、正义【XI】"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),s('<h1 id="正义" tabindex="-1">正义 <a class="header-anchor" href="#正义" aria-label="Permalink to &quot;正义&quot;">​</a></h1><p>正义</p><p>S+9600<br> 替身外貌：<br> 主体为白色，正义是完全由雾组成的替身，会在敌人面前伪装成一团巨大的雾，大到足以包围一个小墓地。当它被具体化时，看起来像戴着一顶宝石大皇冠的骷髅幽灵，头上和手上都像长袍一样雾气缭绕，像极了一个权力很大的王者。</p><p>替身数据：<br> 破坏力D<br> 速度E（偏斜防御）<br> 射程A<br> 持续力A<br> 精密动作性E<br> 成长性E</p><p>替身对应主属性：决心</p><p>替身能力：</p><p>元素化替身：正义的身体是雾构成的，攻击正义只会导致雾被打散，不会对本体造成任何伤害。反过来，当本体被击败时，正义会直接消失。</p><p>控身幻雾：正义能将雾扩散开来，让雾覆盖一个半径为【决心×270】米的球形范围，正义能在这个范围内制造出十分真实和详细的幻觉，即便是创造一个完整的城市幻象，包含其中的每个人以及人的细节与动作，此外在这个范围内如果有目标有仍何部位受伤，替身使者可以用一个标准动作控制正义钻入到所有目标的伤口内，目标以强韧豁免对替身使者的替身使用检定，不造成伤害，对抗失败后伤口部位为中心的体积1范围的身体都会被正义完全控制，即便是死了也会被其所控制，只不过此时无法控制尸体使用其生前的任何能力，也几乎无法将其当具有战斗力的单位去攻击他人，只能用于搬运杂物之类的，以上效果视为S级幻象来源效果和S级创伤来源的支配效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
